def _base64url_encode(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b'=').decode('utf-8')


def _base64url_decode(s: str) -> bytes:
    padding = 4 - len(s) % 4
    if padding != 4:
        s += '=' * padding
    return base64.urlsafe_b64decode(s)


class HMACAlgorithm:
    """HMAC-based signing algorithms (HS256, HS384, HS512)."""

    HASH_FUNCTIONS = {
        'HS256': hashlib.sha256,
        'HS384': hashlib.sha384,
        'HS512': hashlib.sha512,
    }

    def __init__(self, algorithm: str):
        if algorithm not in self.HASH_FUNCTIONS:
            raise JWTAlgorithmError(f"Unsupported HMAC algorithm: {algorithm}")
        self.algorithm = algorithm
        self.hash_func = self.HASH_FUNCTIONS[algorithm]

    def sign(self, message: bytes, key: str) -> bytes:
        return hmac.new(
            key.encode('utf-8') if isinstance(key, str) else key,
            message,
            self.hash_func
        ).digest()

    def verify(self, message: bytes, signature: bytes, key: str) -> bool:
        expected = self.sign(message, key)
        return hmac.compare_digest(signature, expected)


class RSAAlgorithm:
    """RSA-based signing algorithms (RS256, RS384, RS512)."""

    HASH_NAMES = {
        'RS256': 'SHA-256',
        'RS384': 'SHA-384',
        'RS512': 'SHA-512',
    }

    HASH_MODULES = {
        'RS256': hashlib.sha256,
        'RS384': hashlib.sha384,
        'RS512': hashlib.sha512,
    }

    def __init__(self, algorithm: str):
        if algorithm not in self.HASH_NAMES:
            raise JWTAlgorithmError(f"Unsupported RSA algorithm: {algorithm}")
        self.algorithm = algorithm
        self.hash_name = self.HASH_NAMES[algorithm]
        self.hash_func = self.HASH_MODULES[algorithm]
        try:
            from cryptography.hazmat.primitives import hashes, serialization
            from cryptography.hazmat.primitives.asymmetric import padding as asym_padding
            self._hashes = hashes
            self._serialization = serialization
            self._padding = asym_padding
        except ImportError:
            raise JWTAlgorithmError(
                "cryptography package is required for RSA algorithms. "
                "Install it with: pip install cryptography"
            )

    def _load_private_key(self, key):
        if hasattr(key, 'sign'):
            return key
        if isinstance(key, str):
            key = key.encode('utf-8')
        return self._serialization.load_pem_private_key(key, password=None)

    def _load_public_key(self, key):
        if hasattr(key, 'verify'):
            return key
        if isinstance(key, str):
            key = key.encode('utf-8')
        try:
            return self._serialization.load_pem_public_key(key)
        except Exception:
            try:
                cert = self._serialization.load_pem_private_key(key, password=None)
                return cert.public_key()
            except Exception:
                raise JWTDecodeError("Unable to load public key")

    def _get_hash(self):
        hash_map = {
            'SHA-256': self._hashes.SHA256(),
            'SHA-384': self._hashes.SHA384(),
            'SHA-512': self._hashes.SHA512(),
        }
        return hash_map[self.hash_name]

    def sign(self, message: bytes, key) -> bytes:
        private_key = self._load_private_key(key)
        return private_key.sign(
            message,
            self._padding.PKCS1v15(),
            self._get_hash()
        )

    def verify(self, message: bytes, signature: bytes, key) -> bool:
        public_key = self._load_public_key(key)
        try:
            public_key.verify(
                signature,
                message,
                self._padding.PKCS1v15(),
                self._get_hash()
            )
            return True
        except Exception:
            return False


class ES256Algorithm:
    """ECDSA-based signing algorithm (ES256, ES384, ES512)."""

    CURVE_NAMES = {
        'ES256': 'SECP256R1',
        'ES384': 'SECP384R1',
        'ES512': 'SECP521R1',
    }

    HASH_MODULES = {
        'ES256': 'SHA-256',
        'ES384': 'SHA-384',
        'ES512': 'SHA-512',
    }

    SIG_LENGTHS = {
        'ES256': 64,
        'ES384': 96,
        'ES512': 132,
    }

    def __init__(self, algorithm: str):
        if algorithm not in self.CURVE_NAMES:
            raise JWTAlgorithmError(f"Unsupported ECDSA algorithm: {algorithm}")
        self.algorithm = algorithm
        try:
            from cryptography.hazmat.primitives import hashes, serialization
            from cryptography.hazmat.primitives.asymmetric import ec
            from cryptography.hazmat.primitives.asymmetric.utils import (
                decode_dss_signature, encode_dss_signature
            )
            self._hashes = hashes
            self._serialization = serialization
            self._ec = ec
            self._decode_dss = decode_dss_signature
            self._encode_dss = encode_dss_signature
        except ImportError:
            raise JWTAlgorithmError(
                "cryptography package is required for ECDSA algorithms."
            )

    def _get_hash(self):
        hash_map = {
            'SHA-256': self._hashes.SHA256(),
            'SHA-384': self._hashes.SHA384(),
            'SHA-512': self._hashes.SHA512(),
        }
        return hash_map[self.HASH_MODULES[self.algorithm]]

    def _load_private_key(self, key):
        if hasattr(key, 'sign'):
            return key
        if isinstance(key, str):
            key = key.encode('utf-8')
        return self._serialization.load_pem_private_key(key, password=None)

    def _load_public_key(self, key):
        if hasattr(key, 'verify'):
            return key
        if isinstance(key, str):
            key = key.encode('utf-8')
        try:
            return self._serialization.load_pem_public_key(key)
        except Exception:
            try:
                priv = self._serialization.load_pem_private_key(key, password=None)
                return priv.public_key()
            except Exception:
                raise JWTDecodeError("Unable to load EC public key")

    def sign(self, message: bytes, key) -> bytes:
        private_key = self._load_private_key(key)
        der_sig = private_key.sign(
            message,
            self._ec.ECDSA(self._get_hash())
        )
        r, s = self._decode_dss(der_sig)
        sig_len = self.SIG_LENGTHS[self.algorithm]
        half = sig_len // 2
        r_bytes = r.to_bytes(half, byteorder='big')
        s_bytes = s.to_bytes(half, byteorder='big')
        return r_bytes + s_bytes

    def verify(self, message: bytes, signature: bytes, key) -> bool:
        public_key = self._load_public_key(key)
        sig_len = self.SIG_LENGTHS[self.algorithm]
        half = sig_len // 2
        if len(signature) != sig_len:
            return False
        r = int.from_bytes(signature[:half], byteorder='big')
        s = int.from_bytes(signature[half:], byteorder='big')
        der_sig = self._encode_dss(r, s)
        try:
            public_key.verify(
                der_sig,
                message,
                self._ec.ECDSA(self._get_hash())
            )
            return True
        except Exception:
            return False


ALGORITHM_MAP = {}


def _get_algorithm(alg_name: str):
    """Get or create an algorithm instance."""
    if alg_name in ALGORITHM_MAP:
        return ALGORITHM_MAP[alg_name]

    if alg_name.startswith('HS'):
        algo = HMACAlgorithm(alg_name)
    elif alg_name.startswith('RS'):
        algo = RSAAlgorithm(alg_name)
    elif alg_name.startswith('ES'):
        algo = ES256Algorithm(alg_name)
    else:
        raise JWTAlgorithmError(f"Unsupported algorithm: {alg_name}")

    ALGORITHM_MAP[alg_name] = algo
    return algo


