class JWTWrapper:
    """Flask JWT library wrapper supporting multiple signing algorithms."""

    def __init__(self, app: Optional[Flask] = None, config: Optional[JWTConfig] = None):
        self.config = config or JWTConfig()
        self._error_handlers = {}
        self.app = None
        if app is not None:
            self.init_app(app)

    def init_app(self, app: Flask):
        """Initialize with Flask app."""
        self.app = app
        app.extensions['jwt_wrapper'] = self

        # Load config from Flask app config
        if 'JWT_SECRET_KEY' in app.config:
            self.config.default_key = app.config['JWT_SECRET_KEY']
        if 'JWT_ALGORITHM' in app.config:
            self.config.default_algorithm = app.config['JWT_ALGORITHM']
        if 'JWT_ALLOWED_ALGORITHMS' in app.config:
            self.config.allowed_algorithms = app.config['JWT_ALLOWED_ALGORITHMS']
        if 'JWT_LEEWAY' in app.config:
            self.config.leeway = app.config['JWT_LEEWAY']
        if 'JWT_VERIFY_EXP' in app.config:
            self.config.verify_exp = app.config['JWT_VERIFY_EXP']
        if 'JWT_TOKEN_LOCATION' in app.config:
            self.config.token_location = app.config['JWT_TOKEN_LOCATION']
        if 'JWT_HEADER_NAME' in app.config:
            self.config.header_name = app.config['JWT_HEADER_NAME']
        if 'JWT_HEADER_PREFIX' in app.config:
            self.config.header_prefix = app.config['JWT_HEADER_PREFIX']

        # Register error handlers
        @app.errorhandler(JWTError)
        def handle_jwt_error(e):
            return jsonify({'error': str(e), 'type': type(e).__name__}), 401

    def register_algorithm(self, name: str, algorithm: str, key: Union[str, bytes],
                           issuer: Optional[str] = None, audience: Optional[str] = None):
        """Register an algorithm configuration for a named source."""
        self.config.algorithms[name] = AlgorithmConfig(
            algorithm=algorithm,
            key=key,
            issuer=issuer,
            audience=audience
        )
        if algorithm not in self.config.allowed_algorithms:
            self.config.allowed_algorithms.append(algorithm)

    def encode(self, payload: dict, algorithm: Optional[str] = None,
               key: Optional[Union[str, bytes]] = None,
               headers: Optional[dict] = None) -> str:
        """Encode a payload into a JWT token."""
        alg = algorithm or self.config.default_algorithm
        signing_key = key or self.config.default_key

        if signing_key is None:
            raise JWTError("No signing key provided")

        # Build header
        header = {'alg': alg, 'typ': 'JWT'}
        if headers:
            header.update(headers)

        # Add timing claims if not present
        now = int(time.time())
        if 'iat' not in payload:
            payload['iat'] = now

        header_b64 = _base64url_encode(json.dumps(header, separators=(',', ':')).encode('utf-8'))
        payload_b64 = _base64url_encode(json.dumps(payload, separators=(',', ':')).encode('utf-8'))

        signing_input = f"{header_b64}.{payload_b64}".encode('utf-8')

        algo_impl = _get_algorithm(alg)
        signature = algo_impl.sign(signing_input, signing_key)
        signature_b64 = _base64url_encode(signature)

        return f"{header_b64}.{payload_b64}.{signature_b64}"

    def decode(self, token: str, key: Optional[Union[str, bytes]] = None,
               algorithms: Optional[list] = None,
               verify_exp: Optional[bool] = None,
               verify_signature: bool = True,
               audience: Optional[str] = None,
               issuer: Optional[str] = None) -> dict:
        """Decode and verify a JWT token."""
        allowed_algs = algorithms or self.config.allowed_algorithms
        do_verify_exp = verify_exp if verify_exp is not None else self.config.verify_exp

        # Split token
        parts = token.strip().split('.')
        if len(parts) != 3:
            raise JWTDecodeError("Invalid token format: expected 3 parts")

        header_b64, payload_b64, signature_b64 = parts

        # Decode header
        try:
            header = json.loads(_base64url_decode(header_b64))
        except (json.JSONDecodeError, Exception) as e:
            raise JWTDecodeError(f"Invalid token header: {e}")

        # Check algorithm
        token_alg = header.get('alg')
        if not token_alg:
            raise JWTDecodeError("Token header missing 'alg' field")

        if token_alg == 'none':
            raise JWTAlgorithmError("Algorithm 'none' is not allowed")

        if token_alg not in allowed_algs:
            raise JWTAlgorithmError(
                f"Algorithm '{token_alg}' is not in the allowed list: {allowed_algs}"
            )

        # Decode payload
        try:
            payload = json.loads(_base64url_decode(payload_b64))
        except (json.JSONDecodeError, Exception) as e:
            raise JWTDecodeError(f"Invalid token payload: {e}")

        # Verify signature
        if verify_signature:
            verification_key = key or self._resolve_key(token_alg, header, payload)
            if verification_key is None:
                raise JWTError("No verification key available")

            signing_input = f"{header_b64}.{payload_b64}".encode('utf-8')
            signature = _base64url_decode(signature_b64)

            algo_impl = _get_algorithm(token_alg)
            if not algo_impl.verify(signing_input, signature, verification_key):
                raise JWTInvalidSignatureError("Token signature verification failed")

        # Verify claims
        self._verify_claims(payload, do_verify_exp, audience, issuer)

        return payload

    def _resolve_key(self, algorithm: str, header: dict, payload: dict) -> Optional[Union[str, bytes]]:
        """Resolve the verification key based on token properties."""
        # Check if there's a kid (key ID) in the header
        kid = header.get('kid')

        # Try to find a matching algorithm config
        for name, algo_config in self.config.algorithms.items():
            if algo_config.algorithm == algorithm:
                # If kid is specified, match by name
                if kid and kid == name:
                    return algo_config.key
                # If issuer is specified, match by issuer
                iss = payload.get('iss')
                if algo_config.issuer and iss and algo_config.issuer == iss:
                    return algo_config.key

        # If no specific match, find first config matching the algorithm
        for name, algo_config in self.config.algorithms.items():
            if algo_config.algorithm == algorithm:
                return algo_config.key

        # Fall back to default key
        return self.config.default_key

    def _verify_claims(self, payload: dict, verify_exp: bool,
                       audience: Optional[str], issuer: Optional[str]):
        """Verify standard JWT claims."""
        now = int(time.time())

        # Check required claims
        for claim in self.config.required_claims:
            if claim not in payload:
                raise JWTDecodeError(f"Missing required claim: {claim}")

        # Verify expiration
        if verify_exp and 'exp' in payload:
            exp = payload['exp']
            if not isinstance(exp, (int, float)):
                raise JWTDecodeError("Invalid 'exp' claim format")
            if now > exp + self.config.leeway:
                raise JWTExpiredError(
                    f"Token expired at {exp}, current time is {now}"
                )

        # Verify not before
        if self.config.verify_nbf and 'nbf' in payload:
            nbf = payload['nbf']
            if not isinstance(nbf, (int, float)):
                raise JWTDecodeError("Invalid 'nbf' claim format")
            if now < nbf - self.config.leeway:
                raise JWTError(
                    f"Token not valid before {nbf}, current time is {now}"
                )

        # Verify issuer
        check_issuer = issuer
        if self.config.verify_iss and not check_issuer:
            # Try to get expected issuer from algorithm configs
            for name, algo_config in self.config.algorithms.items():
                if algo_config.issuer:
                    check_issuer = algo_config.issuer
                    break

        if check_issuer:
            token_iss = payload.get('iss')
            if token_iss != check_issuer:
                raise JWTDecodeError(
                    f"Invalid issuer: expected '{check_issuer}', got '{token_iss}'"
                )

        # Verify audience
        check_audience = audience
        if self.config.verify_aud and not check_audience:
            for name, algo_config in self.config.algorithms.items():
                if algo_config.audience:
                    check_audience = algo_config.audience
                    break

        if check_audience:
            token_aud = payload.get('aud')
            if isinstance(token_aud, list):
                if check_audience not in token_aud:
                    raise JWTDecodeError(
                        f"Invalid audience: '{check_audience}' not in {token_aud}"
                    )
            elif token_aud != check_audience:
                raise JWTDecodeError(
                    f"Invalid audience: expected '{check_audience}', got '{token_aud}'"
                )

    def _extract_token_from_request(self, req: Request) -> Optional[str]:
        """Extract JWT token from the Flask request."""
        location = self.config.token_location

        if location == 'header':
            auth_header = req.headers.get(self.config.header_name)
            if auth_header:
                prefix = self.config.header_prefix
                if prefix:
                    parts = auth_header.split()
                    if len(parts) == 2 and parts[0] == prefix:
                        return parts[1]
                    elif len(parts) == 1:
                        return parts[0]
                else:
                    return auth_header
        elif location == 'query':
            return req.args.get(self.config.query_param)
        elif location == 'cookie':
            return req.cookies.get(self.config.cookie_name)

        return None

    def get_token_from_request(self) -> str:
        """Get token from current request or raise error."""
        token = self._extract_token_from_request(request)
        if not token:
            raise JWTDecodeError(
                f"Missing JWT token in {self.config.token_location}"
            )
        return token

    def jwt_required(self, fn=None, *, algorithms=None, audience=None, issuer=None):
        """Decorator to require a valid JWT token for a route."""
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                token = self.get_token_from_request()
                payload = self.decode(
                    token,
                    algorithms=algorithms,
                    audience=audience,
                    issuer=issuer
                )
                g.jwt_payload = payload
                g.jwt_identity = payload.get('sub') or payload.get('identity')
                return f(*args, **kwargs)
            return decorated_function

        if fn is not None:
            return decorator(fn)
        return decorator

    def jwt_optional(self, fn=None, *, algorithms=None):
        """Decorator that optionally processes a JWT token if present."""
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                token = self._extract_token_from_request(request)
                if token:
                    try:
                        payload = self.decode(token, algorithms=algorithms)
                        g.jwt_payload = payload
                        g.jwt_identity = payload.get('sub') or payload.get('identity')
                    except JWTError:
                        g.jwt_payload = None
                        g.jwt_identity = None
                else:
                    g.jwt_payload = None
                    g.jwt_identity = None
                return f(*args, **kwargs)
            return decorated_function

        if fn is not None:
            return decorator(fn)
        return decorator

    def require_claims(self, *claims):
        """Decorator to require specific claims in the JWT payload."""
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                payload = getattr(g, 'jwt_payload', None)
                if payload is None:
                    raise JWTDecodeError("No JWT payload available")
                for claim in claims:
                    if claim not in payload:
                        raise JWTDecodeError(f"Missing required claim: {claim}")
                return f(*args, **kwargs)
            return decorated_function
        return decorator

    def require_roles(self, *roles):
        """Decorator to require specific roles in the JWT payload."""
        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                payload = getattr(g, 'jwt_payload', None)
                if payload is None:
                    raise JWTDecodeError("No JWT payload available")
                user_roles = payload.get('roles', [])
                if isinstance(user_roles, str):
                    user_roles = [user_roles]
                if not any(role in user_roles for role in roles):
                    raise JWTError(f"Insufficient permissions. Required roles: {roles}")
                return f(*args, **kwargs)
            return decorated_function
        return decorator

    def create_access_token(self, identity: str, claims: Optional[dict] = None,
                            expires_in: int = 3600, algorithm: Optional[str] = None,
                            key: Optional[Union[str, bytes]] = None) -> str:
        """Create an access token for the given identity."""
        now = int(time.time())
        payload = {
            'sub': identity,
            'iat': now,
            'exp': now + expires_in,
            'type': 'access'
        }
        if claims:
            payload.update(claims)

        return self.encode(payload, algorithm=algorithm, key=key)

    def create_refresh_token(self, identity: str, claims: Optional[dict] = None,
                             expires_in: int = 2592000, algorithm: Optional[str] = None,
                             key: Optional[Union[str, bytes]] = None) -> str:
        """Create a refresh token for the given identity."""
        now = int(time.time())
        payload = {
            'sub': identity,
            'iat': now,
            'exp': now + expires_in,
            'type': 'refresh'
        }
        if claims:
            payload.update(claims)

        return self.encode(payload, algorithm=algorithm, key=key)

    def get_jwt_identity(self) -> Optional[str]:
        """Get the identity from the current JWT."""
        return getattr(g, 'jwt_identity', None)

    def get_jwt_claims(self) -> Optional[dict]:
        """Get the full claims from the current JWT."""
        return getattr(g, 'jwt_payload', None)


# Convenience function
def create_jwt_wrapper(app: Flask, **kwargs) -> JWTWrapper:
    """Create and initialize a JWTWrapper with the given Flask app."""
    config = JWTConfig(**kwargs)
    wrapper = JWTWrapper(app=app, config=config)
    return wrapper


