def create_demo_app():
    """Create a demo Flask app showcasing the JWT wrapper."""
    app = Flask(__name__)
    app.config['JWT_SECRET_KEY'] = 'super-secret-key-for-demo'

    jwt = JWTWrapper(app)

    # Register HS256 for internal services
    jwt.register_algorithm(
        name='internal',
        algorithm='HS256',
        key='internal-service-secret-key',
        issuer='internal-auth-service'
    )

    # For demo we also register a second HS384 source
    jwt.register_algorithm(
        name='partner',
        algorithm='HS384',
        key='partner-secret-key-384',
        issuer='partner-service'
    )

    @app.route('/login', methods=['POST'])
    def login():
        data = request.get_json() or {}
        username = data.get('username', 'demo_user')
        role = data.get('role', 'user')

        access_token = jwt.create_access_token(
            identity=username,
            claims={'roles': [role], 'iss': 'internal-auth-service'},
            algorithm='HS256',
            key='internal-service-secret-key'
        )
        refresh_token = jwt.create_refresh_token(
            identity=username,
            algorithm='HS256',
            key='internal-service-secret-key'
        )

        return jsonify({
            'access_token': access_token,
            'refresh_token': refresh_token
        })

    @app.route('/protected')
    @jwt.jwt_required
    def protected():
        identity = jwt.get_jwt_identity()
        claims = jwt.get_jwt_claims()
        return jsonify({
            'message': f'Hello, {identity}!',
            'claims': claims
        })

    @app.route('/admin')
    @jwt.jwt_required
    @jwt.require_roles('admin')
    def admin_only():
        identity = jwt.get_jwt_identity()
        return jsonify({
            'message': f'Welcome admin: {identity}!'
        })

    @app.route('/optional')
    @jwt.jwt_optional
    def optional_auth():
        identity = jwt.get_jwt_identity()
        if identity:
            return jsonify({'message': f'Hello, {identity}!'})
        return jsonify({'message': 'Hello, anonymous!'})

    @app.route('/health')
    def health():
        return jsonify({'status': 'healthy'})

    return app, jwt


if __name__ == '__main__':
    app, jwt_wrapper = create_demo_app()

    # Quick self-test
    print("=== JWT Wrapper Self-Test ===\n")

    # Test HS256
    print("--- HS256 Test ---")
    token_hs256 = jwt_wrapper.encode(
        {'sub': 'user123', 'exp': int(time.time()) + 3600, 'iss': 'internal-auth-service', 'roles': ['user']},
        algorithm='HS256',
        key='internal-service-secret-key'
    )
    print(f"Token: {token_hs256[:50]}...")
    decoded = jwt_wrapper.decode(token_hs256, key='internal-service-secret-key', algorithms=['HS256'])
    print(f"Decoded: {decoded}\n")

    # Test HS384
    print("--- HS384 Test ---")
    token_hs384 = jwt_wrapper.encode(
        {'sub': 'partner_user', 'exp': int(time.time()) + 3600, 'iss': 'partner-service'},
        algorithm='HS384',
        key='partner-secret-key-384'
    )
    print(f"Token: {token_hs384[:50]}...")
    decoded = jwt_wrapper.decode(token_hs384, key='partner-secret-key-384', algorithms=['HS384'])
    print(f"Decoded: {decoded}\n")

    # Test auto key resolution
    print("--- Auto Key Resolution Test ---")
    decoded_auto = jwt_wrapper.decode(token_hs256, algorithms=['HS256'])
    print(f"Auto-resolved (HS256): {decoded_auto}\n")

    # Test expired token
    print("--- Expired Token Test ---")
    expired_token = jwt_wrapper.encode(
        {'sub': 'user123', 'exp': int(time.time()) - 100},
        algorithm='HS256',
        key='internal-service-secret-key'
    )
    try:
        jwt_wrapper.decode(expired_token, key='internal-service-secret-key', algorithms=['HS256'])
        print("ERROR: Should have raised JWTExpiredError")
    except JWTExpiredError as e:
        print(f"Correctly caught: {e}\n")

    # Test invalid signature
    print("--- Invalid Signature Test ---")
    try:
        jwt_wrapper.decode(token_hs256, key='wrong-key', algorithms=['HS256'])
        print("ERROR: Should have raised JWTInvalidSignatureError")
    except JWTInvalidSignatureError as e:
        print(f"Correctly caught: {e}\n")

    # Test algorithm restriction
    print("--- Algorithm Restriction Test ---")
    try:
        jwt_wrapper.decode(token_hs256, key='internal-service-secret-key', algorithms=['RS256'])
        print("ERROR: Should have raised JWTAlgorithmError")
    except JWTAlgorithmError as e:
        print(f"Correctly caught: {e}\n")

    # Test access/refresh tokens
    print("--- Access/Refresh Token Test ---")
    access = jwt_wrapper.create_access_token('testuser', claims={'roles': ['admin']})
    refresh = jwt_wrapper.create_refresh_token('testuser')
    print(f"Access token payload: {jwt_wrapper.decode(access)}")
    print(f"Refresh token payload: {jwt_wrapper.decode(refresh)}\n")

    # Test RSA if cryptography is available
    try:
        from cryptography.hazmat.primitives.asymmetric import rsa
        from cryptography.hazmat.primitives import serialization

        print("--- RS256 Test ---")
        private_key = rsa.generate_private_key(
            public_exponent=65537,
            key_size=2048,
        )
        private_pem = private_key.private_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PrivateFormat.PKCS8,
            encryption_algorithm=serialization.NoEncryption()
        )
        public_pem = private_key.public_key().public_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PublicFormat.SubjectPublicKeyInfo
        )

        jwt_wrapper.register_algorithm(
            name='public_api',
            algorithm='RS256',
            key=public_pem,
            issuer='public-api'
        )

        token_rs256 = jwt_wrapper.encode(
            {'sub': 'api_user', 'exp': int(time.time()) + 3600, 'iss': 'public-api'},
            algorithm='RS256',
            key=private_pem
        )
        print(f"RS256 Token: {token_rs256[:50]}...")
        decoded_rs256 = jwt_wrapper.decode(
            token_rs256, key=public_pem, algorithms=['RS256']
        )
        print(f"RS256 Decoded: {decoded_rs256}\n")

        # Test ECDSA
        from cryptography.hazmat.primitives.asymmetric import ec

        print("--- ES256 Test ---")
        ec_private_key = ec.generate_private_key(ec.SECP256R1())
        ec_private_pem = ec_private_key.private_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PrivateFormat.PKCS8,
            encryption_algorithm=serialization.NoEncryption()
        )
        ec_public_pem = ec_private_key.public_key().public_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PublicFormat.SubjectPublicKeyInfo
        )

        token_es256 = jwt_wrapper.encode(
            {'sub': 'ec_user', 'exp': int(time.time()) + 3600},
            algorithm='ES256',
            key=ec_private_pem
        )
        print(f"ES256 Token: {token_es256[:50]}...")
        decoded_es256 = jwt_wrapper.decode(
            token_es256, key=ec_public_pem, algorithms=['ES256']
        )
        print(f"ES256 Decoded: {decoded_es256}\n")

    except ImportError:
        print("(Skipping RSA/ECDSA tests - cryptography package not installed)\n")

    print("=== All Tests Passed ===\n")
    print("Starting Flask demo server on http://localhost:5000")
    print("Try: POST /login, GET /protected (with Bearer token), GET /admin, GET /optional")
    app.run(debug=True, port=5000)